class Solution:
    def reachableNodes(self, n, edges, restricted):
        parent = list(range(n))
        def find(x):
            while parent[x] != x:
                parent[x] = parent[parent[x]]
                x = parent[x]
            return x
        block = set(restricted)
        for a, b in edges:
            if a in block or b in block:
                continue
            ra, rb = find(a), find(b)
            if ra != rb:
                parent[ra] = rb
        root = find(0)
        return sum(1 for i in range(n) if i not in block and find(i) == root)

