class Solution:
    def reachableNodes(self, n, edges, restricted):
        from collections import defaultdict, deque
        block = set(restricted)
        g = defaultdict(list)
        for a, b in edges:
            g[a].append(b)
            g[b].append(a)
        seen = {0}
        q = deque([0])
        while q:
            u = q.popleft()
            for v in g[u]:
                if v not in seen and v not in block:
                    seen.add(v)
                    q.append(v)
        return len(seen)

