var reachableNodes = function(n, edges, restricted) {
    const block = new Set(restricted);
    const g = Array.from({length: n}, () => []);
    for (const [a, b] of edges) { g[a].push(b); g[b].push(a); }
    const seen = new Uint8Array(n);
    seen[0] = 1;
    const stack = [0];
    let count = 0;
    while (stack.length) {
        const u = stack.pop();
        count++;
        for (const v of g[u]) {
            if (!seen[v] && !block.has(v)) { seen[v] = 1; stack.push(v); }
        }
    }
    return count;
};
